namespace sv_4e24dd665438499fa9324282908ec3b4.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@page "/chat"
@rendermode InteractiveServer
@using sv_4e24dd665438499fa9324282908ec3b4.Services
@inject IChatService ChatService
@inject IJSRuntime JS

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    @* ─── Left Sidebar: Channel List ─── *@
    <aside class="sidebar @(threadOpen ? "sidebar--thread-open" : "")">
        <h3 class="sidebar__title">Channels</h3>
        <ul class="channel-list">
            @if (channels is not null)
            {
                @foreach (var ch in channels)
                {
                    <li class="channel-item @(ch.Id == activeChannelId ? "channel-item--active" : "")"
                        @onclick="() => SelectChannelAsync(ch.Id)">
                        <div class="channel-item__header">
                            <span class="channel-item__name"># @ch.Name</span>
                            @if (ch.UnreadCount > 0)
                            {
                                <span class="badge">@ch.UnreadCount</span>
                            }
                        </div>
                        <span class="channel-item__desc">@Truncate(ch.Description, 50)</span>
                    </li>
                }
            }
        </ul>
    </aside>

    @* ─── Main Message Area ─── *@
    <section class="main-area @(threadOpen ? "main-area--thread-open" : "")">
        @if (activeChannel is not null)
        {
            <header class="main-header">
                <h2 class="main-header__name"># @activeChannel.Name</h2>
                <p class="main-header__desc">@activeChannel.Description</p>
            </header>

            <div class="message-list" @ref="messageListRef" @onscroll="OnMessageListScroll">
                @if (loadingOlder)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @if (messages is not null)
                {
                    @foreach (var msg in messages)
                    {
                        <div class="message" @onmouseenter="() => hoveredMessageId = msg.Id"
                             @onmouseleave="() => { if (hoveredMessageId == msg.Id) hoveredMessageId = null; }">
                            <div class="message__header">
                                <strong class="message__author">@msg.Author</strong>
                                <time class="message__time">@FormatRelativeTime(msg.SentAt)</time>
                            </div>
                            <div class="message__content">@msg.Content</div>

                            @* Reactions *@
                            @if (msg.Reactions?.Count > 0)
                            {
                                <div class="reactions">
                                    @foreach (var r in msg.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                @onclick="() => ReactAsync(msg.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }

                            @* Thread starter indicator *@
                            @if (threadSummaries.TryGetValue(msg.Id, out var summary))
                            {
                                <button class="thread-link" @onclick="() => OpenThreadAsync(msg)">
                                    @summary.ReplyCount @(summary.ReplyCount == 1 ? "reply" : "replies")
                                </button>
                            }

                            @* Hover action buttons *@
                            @if (hoveredMessageId == msg.Id)
                            {
                                <div class="message-actions">
                                    <button class="action-btn" @onclick="() => OpenThreadAsync(msg)">💬 Reply</button>
                                    <div class="emoji-picker-wrapper">
                                        <button class="action-btn" @onclick="() => ToggleEmojiPicker(msg.Id)">😀 React</button>
                                        @if (emojiPickerMessageId == msg.Id)
                                        {
                                            <div class="emoji-picker">
                                                @foreach (var emoji in commonEmojis)
                                                {
                                                    <button class="emoji-pick" @onclick="() => ReactAsync(msg.Id, emoji)">@emoji</button>
                                                }
                                            </div>
                                        }
                                    </div>
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="compose-area">
                <textarea class="compose-input" rows="2" placeholder="Type a message…"
                          @bind="newMessageText" @bind:event="oninput"
                          @onkeydown="OnComposeKeyDown" />
                <button class="send-btn" disabled="@string.IsNullOrWhiteSpace(newMessageText)"
                        @onclick="SendMessageAsync">Send</button>
            </div>
        }
        else
        {
            <div class="empty-state">Select a channel to start chatting</div>
        }
    </section>

    @* ─── Right Panel: Thread View ─── *@
    @if (threadOpen && threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <header class="thread-header">
                <h3>Thread</h3>
                <button class="close-btn" @onclick="CloseThread">✕</button>
            </header>

            <div class="thread-root">
                <strong>@threadRootMessage.Author</strong>
                <time class="message__time">@FormatRelativeTime(threadRootMessage.SentAt)</time>
                <p>@threadRootMessage.Content</p>
            </div>

            <div class="thread-replies">
                @if (threadReplies is not null)
                {
                    @foreach (var reply in threadReplies)
                    {
                        <div class="message">
                            <div class="message__header">
                                <strong class="message__author">@reply.Author</strong>
                                <time class="message__time">@FormatRelativeTime(reply.SentAt)</time>
                            </div>
                            <div class="message__content">@reply.Content</div>
                            @if (reply.Reactions?.Count > 0)
                            {
                                <div class="reactions">
                                    @foreach (var r in reply.Reactions)
                                    {
                                        <button class="reaction-badge"
                                                @onclick="() => ReactAsync(reply.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="compose-area">
                <textarea class="compose-input" rows="2" placeholder="Reply in thread…"
                          @bind="threadReplyText" @bind:event="oninput"
                          @onkeydown="OnThreadReplyKeyDown" />
                <button class="send-btn" disabled="@string.IsNullOrWhiteSpace(threadReplyText)"
                        @onclick="SendThreadReplyAsync">Reply</button>
            </div>
        </aside>
    }
</div>

@code {
    private const int PageSize = 30;
    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "😮", "👀"];

    // Data
    private List<Channel>? channels;
    private List<Message>? messages;
    private Channel? activeChannel;
    private int? activeChannelId;
    private Dictionary<int, ThreadSummary> threadSummaries = new();

    // Thread panel
    private bool threadOpen;
    private Message? threadRootMessage;
    private List<Message>? threadReplies;
    private string threadReplyText = string.Empty;

    // Compose
    private string newMessageText = string.Empty;

    // UI state
    private int? hoveredMessageId;
    private int? emojiPickerMessageId;
    private bool loadingOlder;
    private bool allOlderLoaded;

    private ElementReference messageListRef;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels?.Count > 0)
        {
            await SelectChannelAsync(channels[0].Id);
        }
    }

    // ─── Channel selection ───
    private async Task SelectChannelAsync(int channelId)
    {
        if (activeChannelId == channelId) return;

        activeChannelId = channelId;
        activeChannel = channels?.FirstOrDefault(c => c.Id == channelId);
        messages = null;
        allOlderLoaded = false;
        emojiPickerMessageId = null;

        var loaded = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        messages = loaded;
        if (loaded.Count < PageSize) allOlderLoaded = true;

        BuildThreadSummaries();
        await ChatService.MarkChannelReadAsync(channelId);
        RefreshChannelUnread(channelId);
    }

    private void RefreshChannelUnread(int channelId)
    {
        if (channels is null) return;
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            var ch = channels[idx];
            channels[idx] = ch with { UnreadCount = 0 };
        }
    }

    // ─── Pagination (scroll-to-top) ───
    private async Task OnMessageListScroll()
    {
        if (loadingOlder || allOlderLoaded || messages is null || activeChannelId is null) return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('[blazor-scroll]')?.scrollTop ?? 1");
        if (scrollTop > 0) return;

        loadingOlder = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(activeChannelId.Value, messages.Count, PageSize);
        if (older.Count < PageSize) allOlderLoaded = true;
        messages.InsertRange(0, older);
        BuildThreadSummaries();

        loadingOlder = false;
    }

    // ─── Send message ───
    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(newMessageText) || activeChannelId is null) return;

        var sent = await ChatService.SendMessageAsync(activeChannelId.Value, newMessageText.Trim(), null);
        messages ??= new();
        messages.Add(sent);
        newMessageText = string.Empty;
    }

    private async Task OnComposeKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessageAsync();
        }
    }

    // ─── Reactions ───
    private async Task ReactAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        emojiPickerMessageId = null;

        // Refresh the message list for the current channel to reflect the new reaction
        if (activeChannelId is not null)
        {
            messages = await ChatService.GetMessagesAsync(activeChannelId.Value, 0, messages?.Count ?? PageSize);
        }

        // If thread is open, refresh thread replies too
        if (threadOpen && threadRootMessage is not null)
        {
            threadReplies = await ChatService.GetThreadAsync(threadRootMessage.Id);
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
    }

    // ─── Thread panel ───
    private async Task OpenThreadAsync(Message rootMessage)
    {
        threadRootMessage = rootMessage;
        threadReplies = await ChatService.GetThreadAsync(rootMessage.Id);
        threadReplyText = string.Empty;
        threadOpen = true;
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadReplies = null;
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(threadReplyText) || threadRootMessage is null || activeChannelId is null) return;

        var reply = await ChatService.SendMessageAsync(activeChannelId.Value, threadReplyText.Trim(), threadRootMessage.Id);
        threadReplies ??= new();
        threadReplies.Add(reply);
        threadReplyText = string.Empty;

        // Update thread summary in main list
        if (threadSummaries.ContainsKey(threadRootMessage.Id))
        {
            var s = threadSummaries[threadRootMessage.Id];
            threadSummaries[threadRootMessage.Id] = new ThreadSummary(s.RootMessageId, s.ReplyCount + 1, DateTime.UtcNow);
        }
        else
        {
            threadSummaries[threadRootMessage.Id] = new ThreadSummary(threadRootMessage.Id, 1, DateTime.UtcNow);
        }
    }

    private async Task OnThreadReplyKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    // ─── Thread summary helpers ───
    private void BuildThreadSummaries()
    {
        threadSummaries.Clear();
        if (messages is null) return;

        // Messages with ReplyToId are replies; group them by their root message
        var replies = messages.Where(m => m.ReplyToId is not null).ToList();
        foreach (var group in replies.GroupBy(m => m.ReplyToId!.Value))
        {
            threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt)
            );
        }
    }

    // ─── Formatting helpers ───
    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..(maxLength - 1)] + "…";
}

