    outline: none;
    transition: border-color 0.2s;
}

.compose-input:focus {
    border-color: #1264a3;
}

.send-btn {
    background: #007a5a;
    color: #fff;
    border: none;
    border-radius: 6px;
    padding: 8px 20px;
    font-size: 0.9rem;
    font-weight: 600;
    cursor: pointer;
    align-self: flex-end;
    transition: background 0.15s;
}

.send-btn:hover:not(:disabled) {
    background: #005e44;
}

.send-btn:disabled {
    background: #ccc;
    cursor: not-allowed;
}

/* ─── Loading ─── */
.loading-indicator {
    text-align: center;
    color: #888;
    font-size: 0.85rem;
    padding: 8px;
}

/* ─── Thread Panel ─── */
.thread-panel {
    width: 25%;
    min-width: 280px;
    display: flex;
    flex-direction: column;
    background: #fff;
    border-left: 1px solid #e8e8e8;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #e8e8e8;
    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1.05rem;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.1rem;
    cursor: pointer;
    color: #666;
    padding: 4px 8px;
    border-radius: 4px;
}

.close-btn:hover {
    background: #f0f0f0;
}

.thread-root {
    padding: 12px 16px;
    background: #f8f8f8;
    border-bottom: 1px solid #e8e8e8;
    font-size: 0.9rem;
    flex-shrink: 0;
}

.thread-root p {
    margin: 6px 0 0;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 16px;
}
"}

