toolArgs.file_text:
/* ─── Layout ─── */
.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    color: #1d1c1d;
}

/* ─── Sidebar ─── */
.sidebar {
    width: 20%;
    min-width: 200px;
    background: #3f0e40;
    color: #cfc3cf;
    display: flex;
    flex-direction: column;
    overflow-y: auto;
}

.sidebar__title {
    padding: 16px 16px 8px;
    font-size: 1.1rem;
    color: #fff;
    margin: 0;
}

.channel-list {
    list-style: none;
    margin: 0;
    padding: 0;
}

.channel-item {
    padding: 8px 16px;
    cursor: pointer;
    border-left: 3px solid transparent;
    transition: background 0.15s;
}

.channel-item:hover {
    background: rgba(255, 255, 255, 0.08);
}

.channel-item--active {
    background: rgba(255, 255, 255, 0.15);
    border-left-color: #fff;
}

.channel-item__header {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-item__name {
    font-weight: 600;
    font-size: 0.95rem;
    color: #fff;
}

.channel-item__desc {
    font-size: 0.78rem;
    color: #b5a9b5;
    display: block;
    margin-top: 2px;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.badge {
    background: #e01e5a;
    color: #fff;
    font-size: 0.72rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

/* ─── Main Area ─── */
.main-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-width: 0;
    background: #fff;
    border-right: 1px solid #e8e8e8;
}

.main-area--thread-open {
    max-width: 55%;
}

.main-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e8e8e8;
    flex-shrink: 0;
}

.main-header__name {
    margin: 0;
    font-size: 1.15rem;
}

.main-header__desc {
    margin: 4px 0 0;
    font-size: 0.85rem;
    color: #616061;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 20px;
}

.empty-state {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #888;
    font-size: 1.1rem;
}

/* ─── Messages ─── */
.message {
    position: relative;
    padding: 6px 8px;
    border-radius: 6px;
    transition: background 0.1s;
}

.message:hover {
    background: #f8f8f8;
}

.message__header {
    display: flex;
    align-items: baseline;
    gap: 8px;
}

.message__author {
    font-size: 0.95rem;
}

.message__time {
    font-size: 0.75rem;
